/*
 * fpclassify() test harness — prints (input_hex, classification) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static const char *class_name(int cls)
{
    switch (cls) {
    case FP_ZERO: return "ZERO";
    case FP_SUBNORMAL: return "SUBNORMAL";
    case FP_NORMAL: return "NORMAL";
    case FP_INFINITE: return "INFINITE";
    case FP_NAN: return "NAN";
    default: return "UNKNOWN";
    }
}

static void emit(double x)
{
    int cls = fpclassify(x);
    printf("%016llx %s\n", (unsigned long long)d2u(x), class_name(cls));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

static void test_representative_100(void)
{
    /* --- Section 1: Zero values (2) --- */
    emit(0.0);                                          /* +0.0 */
    emit(-0.0);                                         /* -0.0 */

    /* --- Section 2: Infinite values (4) --- */
    emit_u(0x7ff0000000000000ULL);                      /* +Inf */
    emit_u(0xfff0000000000000ULL);                      /* -Inf */
    emit_u(0x7ff0000000000000ULL - 1);                  /* one ULP below +Inf = DBL_MAX */
    emit_u(0xfff0000000000000ULL - 1);                  /* one ULP toward zero from -Inf = -DBL_MAX */

    /* --- Section 3: NaN values (11) --- */
    emit_u(0x7ff8000000000000ULL);                      /* +qNaN (canonical) */
    emit_u(0x7ff0000000000001ULL);                      /* +sNaN (min payload) */
    emit_u(0xfff8000000000000ULL);                      /* -qNaN */
    emit_u(0xfff0000000000001ULL);                      /* -sNaN */
    emit_u(0x7ff8000000000001ULL);                      /* qNaN with payload 1 */
    emit_u(0x7ff0ffffffffffffULL);                      /* sNaN with max payload */
    emit_u(0x7ff8aaaaaaaaaaaULL);                       /* qNaN with alternating-bit payload */
    emit_u(0xfff8ffffffffffffULL);                      /* -qNaN with max payload */
    emit_u(0x7fffffffffffffffULL);                      /* qNaN with all-ones payload */
    emit_u(0xffffffffffffffffULL);                      /* -qNaN with all-ones payload */
    emit_u(0x7ff4000000000000ULL);                      /* qNaN with mid payload */

    /* --- Section 4: Subnormal (denormal) values (10) --- */
    emit_u(0x0000000000000001ULL);                      /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);                      /* min negative subnormal */
    emit_u(0x000fffffffffffffULL);                      /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);                      /* max negative subnormal */
    emit_u(0x0008000000000000ULL);                      /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);                      /* mid negative subnormal */
    emit_u(0x0004000000000000ULL);                      /* lower-mid positive subnormal */
    emit_u(0x8004000000000000ULL);                      /* lower-mid negative subnormal */
    emit_u(0x0000000000000002ULL);                      /* second smallest positive subnormal */
    emit_u(0x0000800000000000ULL);                      /* upper-quarter subnormal */

    /* --- Section 5: Normal boundary values (8) --- */
    emit(DBL_MIN);                                      /* smallest positive normal: 2^-1022 = 0x0010000000000000 */
    emit(-DBL_MIN);                                     /* smallest negative normal */
    emit_u(0x0010000000000001ULL);                      /* one ULP above DBL_MIN */
    emit_u(0x8010000000000001ULL);                      /* one ULP above -DBL_MIN (toward -Inf) */
    emit(DBL_MAX);                                      /* largest positive normal: 0x7fefffffffffffff */
    emit(-DBL_MAX);                                     /* largest negative normal */
    emit_u(0x7fefffffffffffffULL - 1);                  /* one ULP below DBL_MAX */
    emit_u(0xffefffffffffffffULL - 1);                  /* one ULP below -DBL_MAX (toward zero) */

    /* --- Section 6: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);                      /* one ULP below 1.0 */
    emit(1.0);                                          /* 1.0 exactly */
    emit_u(0x3ff0000000000001ULL);                      /* one ULP above 1.0 */
    emit_u(0x3feffffffff00000ULL);                      /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000100000ULL);                      /* a few ULPs above 1.0 */
    emit(-1.0);                                         /* -1.0 exactly */
    emit_u(0xbfefffffffffffffULL);                      /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);                      /* one ULP away from zero from -1.0 */

    /* --- Section 7: Power-of-2 exponent boundaries (12) --- */
    emit(0.5);                                          /* 2^-1 = 0x3fe0000000000000 */
    emit(-0.5);
    emit(2.0);                                          /* 2^1 = 0x4000000000000000 */
    emit(-2.0);
    emit(4.0);                                          /* 2^2 = 0x4010000000000000 */
    emit(0.25);                                         /* 2^-2 = 0x3fd0000000000000 */
    emit(8.0);                                          /* 2^3 */
    emit(16.0);                                         /* 2^4 */
    emit(0.125);                                        /* 2^-3 */
    emit(1024.0);                                       /* 2^10 */
    emit_u(0x4000000000000001ULL);                      /* one ULP above 2.0 */
    emit_u(0x3fffffffffffffffULL);                      /* one ULP below 2.0 */

    /* --- Section 8: Small normal values (10) --- */
    emit(1.0e-1);
    emit(-1.0e-1);
    emit(1.0e-10);
    emit(1.0e-50);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-200);
    emit(1.0e-300);
    emit(1.0e-307);                                     /* near underflow boundary */
    emit(-1.0e-307);

    /* --- Section 9: Medium normal values (12) --- */
    emit(3.14159265358979323846);                       /* pi */
    emit(-3.14159265358979323846);
    emit(2.71828182845904523536);                       /* e */
    emit(-2.71828182845904523536);
    emit(10.0);
    emit(-10.0);
    emit(100.0);
    emit(-100.0);
    emit(1000.0);
    emit(1.0e6);
    emit(1.0e9);
    emit(-1.0e9);

    /* --- Section 10: Large normal values (13) --- */
    emit(1.0e10);
    emit(-1.0e10);
    emit(1.0e50);
    emit(-1.0e50);
    emit(1.0e100);
    emit(-1.0e100);
    emit(1.0e200);
    emit(-1.0e200);
    emit(1.0e300);
    emit(-1.0e300);
    emit(1.0e307);                                      /* near overflow boundary */
    emit(-1.0e307);
    emit(DBL_MAX * 0.5);                                /* halfway between DBL_MAX/2 and DBL_MAX */

    /* --- Section 11: Additional NaN and Inf boundary patterns (10) --- */
    emit_u(0x7ff8000000000000ULL + 1);                  /* qNaN payload 1 (bit above quiet bit) */
    emit_u(0x7ff0000000000002ULL);                      /* sNaN payload 2 */
    emit_u(0xfff0000000000002ULL);                      /* -sNaN payload 2 */
    emit_u(0x7ff8555555555555ULL);                      /* qNaN with 0x555... payload */
    emit_u(0x7ffaaaaaaaaaaaaaULL);                      /* qNaN with 0xaaa... payload */
    emit_u(0xfff8555555555555ULL);                      /* -qNaN with 0x555... payload */
    emit_u(0x7ff0000000000000ULL + 2);                  /* sNaN payload 2 (same as above but distinct check) */
    emit_u(0x7ff0800000000000ULL);                      /* sNaN with upper-mantissa bit set */
    emit_u(0x7ff7ffffffffffffULL);                      /* sNaN with max payload (quiet bit clear) */
    emit_u(0xfff7ffffffffffffULL);                      /* -sNaN with max payload */
}

/* 8. Edge cases and mixed sweep */
static void test_sweep(void)
{
    double vals[] = {
        -DBL_MAX, -1.0e100, -1.0, -DBL_MIN,
        -DBL_MIN * 0.5, 0.0, DBL_MIN * 0.5,
        DBL_MIN, 1.0, 1.0e100, DBL_MAX
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -100.0;
    double hi =  100.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile int acc = 0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += fpclassify(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %x\n",
           (unsigned long long)d2u(x),
           (unsigned)acc);
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.5);
#else
    test_representative_100();
    test_sweep();
    test_random_300();
#endif
    return 0;
}

