    93→    emit(DBL_MAX);                                      /* largest positive normal: 0x7fefffffffffffff */
    94→    emit(-DBL_MAX);                                     /* largest negative normal */
    95→    emit_u(0x7fefffffffffffffULL - 1);                  /* one ULP below DBL_MAX */
    96→    emit_u(0xffefffffffffffffULL - 1);                  /* one ULP below -DBL_MAX (toward zero) */
    97→
    98→    /* --- Section 6: Near 1.0 ULP density (8) --- */
    99→    emit_u(0x3fefffffffffffffULL);                      /* one ULP below 1.0 */
   100→    emit(1.0);                                          /* 1.0 exactly */
   101→    emit_u(0x3ff0000000000001ULL);                      /* one ULP above 1.0 */
   102→    emit_u(0x3feffffffff00000ULL);                      /* a few ULPs below 1.0 */
   103→    emit_u(0x3ff0000000100000ULL);                      /* a few ULPs above 1.0 */
   104→    emit(-1.0);                                         /* -1.0 exactly */
   105→    emit_u(0xbfefffffffffffffULL);                      /* one ULP toward zero from -1.0 */
   106→    emit_u(0xbff0000000000001ULL);                      /* one ULP away from zero from -1.0 */
   107→
   108→    /* --- Section 7: Power-of-2 exponent boundaries (12) --- */
   109→    emit(0.5);                                          /* 2^-1 = 0x3fe0000000000000 */
   110→    emit(-0.5);
   111→    emit(2.0);                                          /* 2^1 = 0x4000000000000000 */
