   119→    emit_u(0x4000000000000001ULL);                      /* one ULP above 2.0 */
   120→    emit_u(0x3fffffffffffffffULL);                      /* one ULP below 2.0 */
   121→
   122→    /* --- Section 8: Small normal values (10) --- */
   123→    emit(1.0e-1);
   124→    emit(-1.0e-1);
   125→    emit(1.0e-10);
   126→    emit(1.0e-50);
   127→    emit(1.0e-100);
