   162→    emit(-1.0e307);
   163→    emit(DBL_MAX * 0.5);                                /* halfway between DBL_MAX/2 and DBL_MAX */
   164→
   165→    /* --- Section 11: Additional NaN and Inf boundary patterns (10) --- */
   166→    emit_u(0x7ff8000000000000ULL + 1);                  /* qNaN payload 1 (bit above quiet bit) */
   167→    emit_u(0x7ff0000000000002ULL);                      /* sNaN payload 2 */
   168→    emit_u(0xfff0000000000002ULL);                      /* -sNaN payload 2 */
   169→    emit_u(0x7ff8555555555555ULL);                      /* qNaN with 0x555... payload */
   170→    emit_u(0x7ffaaaaaaaaaaaaaULL);                      /* qNaN with 0xaaa... payload */
   171→    emit_u(0xfff8555555555555ULL);                      /* -qNaN with 0x555... payload */
   172→    emit_u(0x7ff0000000000010ULL);                      /* sNaN payload 0x10 */
   173→    emit_u(0x7ff0800000000000ULL);                      /* sNaN with upper-mantissa bit set */
   174→    emit_u(0x7ff7ffffffffffffULL);                      /* sNaN with max payload (quiet bit clear) */
   175→    emit_u(0xfff7ffffffffffffULL);                      /* -sNaN with max payload */
