   178→/* 8. Edge cases and mixed sweep */
   179→static void test_sweep(void)
   180→{
   181→    double vals[] = {
   182→        -DBL_MAX, -1.0e100, -1.0, -DBL_MIN,
   183→        -DBL_MIN * 0.5, 0.0, DBL_MIN * 0.5,
   184→        DBL_MIN, 1.0, 1.0e100, DBL_MAX
   185→    };
   186→    int n = sizeof(vals) / sizeof(vals[0]);
   187→    for (int i = 0; i < n; i++)
   188→        emit(vals[i]);
   189→}
