   191→/* 9. Random sweep: 300 evenly spaced inputs */
   192→static void test_random_300(void)
   193→{
   194→    double lo = -100.0;
   195→    double hi =  100.0;
   196→    int n = 300;
   197→    for (int i = 0; i < n; i++) {
   198→        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
   199→        emit(x);
   200→    }
   201→}
